using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: Default discriminator property renamed "$type" in EF9.
            // Existing documents and raw SQL (WHERE c.Discriminator = 'Blog') require the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: EF9 maps Id directly to JSON "id".
            // Existing documents use "Blog|{key}" format. Preserve via value converter.
            entity.Property(b => b.Id).HasConversion(
                v => "Blog|" + v,
                v => v.StartsWith("Blog|") ? v.Substring(5) : v);

            // Breaking change 3: HasIndex now throws for Cosmos (was silently ignored).
            // REMOVED: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

